<div class="page">

<!-- 헤더 카드 -->
<div class="header-card">
  <div class="brand-row">
    <div>
      <div class="brand">Physical UP 333</div>
      <div class="test-name">333TEST</div>
      <div style="color:rgba(201,168,76,0.4);font-size:8px;letter-spacing:2px;">ELITE SPORTS LAB</div>
    </div>
    <div class="seal">⚾</div>
  </div>
  <div class="divider"></div>
  <div class="code-wrap">
    <div class="code-badge">${p.code}</div>
    <div class="type-row">
      <div class="main-tag">${p.main}</div>
      <span style="font-size:26px;">${$.emoji}</span>
      <div class="sub-name">${T.nick}</div>
    </div>
  </div>
  <div class="wit-box">
    <div class="wit">"${T.wit}"</div>
    <div class="tip">💡 ${T.tip}</div>
  </div>
  <div class="axes">
    <div class="ax" style="background:rgba(79,207,160,0.12)">
      <div class="ax-l" style="color:#4fcfa0">선천 (유전)</div>
      <div class="ax-d" style="color:#4fcfa0">${N(p.scores.store)}</div>
      <div class="ax-n" style="color:#4fcfa0">${p.scores.store}/3</div>
    </div>
    <div class="ax" style="background:rgba(247,149,79,0.12)">
      <div class="ax-l" style="color:#f7954f">대사 (흡수)</div>
      <div class="ax-d" style="color:#f7954f">${N(p.scores.absorb)}</div>
      <div class="ax-n" style="color:#f7954f">${p.scores.absorb}/3</div>
    </div>
    <div class="ax" style="background:rgba(247,111,142,0.12)">
      <div class="ax-l" style="color:#f76f8e">생활 (환경)</div>
      <div class="ax-d" style="color:#f76f8e">${N(p.scores.burn)}</div>
      <div class="ax-n" style="color:#f76f8e">${p.scores.burn}/3</div>
    </div>
  </div>
  <div class="footer-row">
    <div class="footer-date">${D}</div>
    <div class="footer-url">www.physicalup333.com</div>
  </div>
</div>

<!-- 버튼 두 개 -->
<div class="btn-wrap">
  <button class="btn-kakao" onclick="shareKakao()">
    💬 카톡 공유<br/>
    <span style="font-size:10px;font-weight:600">복사 후 카톡 열기</span>
  </button>
  <button class="btn-save" onclick="saveHtml()">
    💾 검사지 저장<br/>
    <span style="font-size:10px;opacity:0.7;font-weight:600">HTML 파일 보관</span>
  </button>
</div>
<div id="kakao-msg" style="display:none;background:#FEE500;border-radius:10px;padding:10px 14px;margin-bottom:16px;text-align:center;font-size:12px;font-weight:700;color:#000;font-family:'Noto Sans KR',sans-serif;">
  ✅ 결과가 복사됐어요!<br/>
  <span style="font-size:11px;font-weight:500">카카오톡 → 채팅창 → 길게 누르기 → 붙여넣기</span>
</div>
<div class="detail-card">
  <div class="detail-header">
    <div class="detail-title">BIO CODE 상세 결과 확인서</div>
    <div class="detail-badge">${p.code}</div>
  </div>

  ${pi}

  <div class="section">
    <div class="section-title">🥗 음식 대책</div>
    ${y.food.map(se=>`<div class="item"><span class="bullet">▸</span><span class="item-text">${se}</span></div>`).join("")}
  </div>

  <div class="section">
    <div class="section-title">💊 영양제 대책</div>
    ${y.supplement.map(se=>`<div class="item"><span class="bullet">▸</span><span class="item-text">${se}</span></div>`).join("")}
  </div>

  <div class="section">
    <div class="section-title">🏃 추천 운동 비율</div>
    <div class="ex-stack">
      ${y.exercise.ratio.map(se=>`<div style="width:${se.pct}%;background:${se.color};display:flex;align-items:center;justify-content:center;min-width:${se.pct>0?2:0}px"><span style="color:#0d1b3e;font-size:8px;font-weight:900">${se.pct>=14?se.pct+"%":""}</span></div>`).join("")}
    </div>
    ${y.exercise.ratio.map(se=>`<div class="ex-row"><div class="ex-dot" style="background:${se.color}"></div><span class="ex-lbl">${se.name.replace(`
`,"·")}</span><span class="ex-pct" style="color:${se.color}">${se.pct}%</span></div>`).join("")}
    <div style="margin-top:8px;padding:8px 12px;background:rgba(201,168,76,0.05);border-radius:8px;border:1px solid rgba(201,168,76,0.15);">
      <span style="color:#8a7040;font-size:11px;">${y.exercise.caution}</span>
    </div>
  </div>

  <div class="section">
    <div class="section-title">✨ ${T.emoji} {ment.nick} 맞춤 포인트</div>
    <div class="point-box"><div class="point-txt">${$.plus}</div></div>
  </div>

  <div class="section">
    <div class="section-title">✅ 생활 습관</div>
    ${y.life.map(se=>`<div class="item"><span class="bullet">▸</span><span class="item-text">${se}</span></div>`).join("")}
  </div>

  <div class="warn-box">
    <div class="warn-txt">⚠️ ${y.caution}</div>
  </div>
</div>

<!-- 하단 -->
<div class="bottom-card">
  <div>
    <div style="color:rgba(201,168,76,0.6);font-size:10px;margin-bottom:2px;">검사일 ${D} · 발급처 Physical UP 333 Physical UP 333</div>
    <div style="color:#c9a84c;font-size:12px;font-weight:700;letter-spacing:1px;">www.physicalup333.com</div>
    <div class="hashtag">#피지컬업333테스트 #Physical UP 333 #BIOCODE</div>
  </div>
  <div class="stamp">
    <div>PHYSICAL</div><div class="mid">UP</div><div>OFFICIAL</div>
  </div>
</div>

</div>

